class Solution {
public:
    ListNode* removeZeroSumSublists(ListNode* head) {
        ListNode* dummy = new ListNode(0);
        dummy->next = head;
        std::unordered_map<int, ListNode*> prefixSum;
        int sum = 0;
        prefixSum[0] = dummy;
        while (head) {
            sum += head->val;
            if (prefixSum.find(sum) != prefixSum.end()) {
                ListNode* node = prefixSum[sum];
                ListNode* tmp = node->next;
                int tmpSum = sum + tmp->val;
                while (tmp != head) {
                    prefixSum.erase(tmpSum);
                    tmp = tmp->next;
                    tmpSum += tmp->val;
                }
                node->next = head->next;
            } else {
                prefixSum[sum] = head;
            }
            head = head->next;
        }
        return dummy->next;
    }
};

